function formatDateInTimeZone(date, timeZone) {
  const parts = new Intl.DateTimeFormat('en-CA', { timeZone, year: 'numeric', month: '2-digit', day: '2-digit' }).formatToParts(date);
  const map = Object.fromEntries(parts.map((part) => [part.type, part.value]));
  return `${map.year}-${map.month}-${map.day}`;
}
return {
  json: {
    backendBaseUrl: 'http://host.docker.internal:3000/api/v1',
    internalToken: 'dev-internal-token',
    source: 'n8n-uc13-daily-operations-report-0700',
    reportDate: formatDateInTimeZone(new Date(), 'Asia/Ho_Chi_Minh'),
    smtpFrom: 'hotel-management@example.com',
    managerEmails: ['manager@example.com'],
    slackWebhookUrl: 'PASTE_SLACK_WEBHOOK_URL_HERE',
    telegramBotToken: 'PASTE_TELEGRAM_BOT_TOKEN_HERE',
    telegramChatId: 'PASTE_TELEGRAM_CHAT_ID_HERE',
    technicalAlertWebhookUrl: 'PASTE_TECH_ALERT_WEBHOOK_URL_HERE',
  },
};

function firstJson(nodeName) {
  const items = $items(nodeName);
  const item = items?.[0]?.json ?? {};
  return item.data ?? item;
}

const config = $('Build Report Config').item.json;
const movements = firstJson('Get Check-in Check-out Data');
const occupancy = firstJson('Get Occupancy Data');
const overdue = firstJson('Get Overdue Payment Data');
const checkIns = movements.checkIns ?? movements.checkInList ?? [];
const checkOuts = movements.checkOuts ?? movements.checkOutList ?? [];
const overdueItems = overdue.items ?? overdue.overduePayments ?? [];
const occupancyRate = occupancy.occupancyRate ?? 0;
const vacantRooms = occupancy.vacantRooms ?? occupancy.availableRooms ?? 0;
const totalRooms = occupancy.totalRooms ?? 0;
const overdueAmount = overdue.totalAmount ?? overdue.outstandingAmount ?? 0;

const checkInRows = checkIns.map((item) => `<tr><td>${item.reservationCode ?? item.code ?? item.id}</td><td>${item.customerName ?? item.customer?.name ?? ''}</td><td>${item.roomName ?? item.room?.name ?? ''}</td><td>${item.checkInAt ?? item.time ?? ''}</td></tr>`).join('');
const checkOutRows = checkOuts.map((item) => `<tr><td>${item.reservationCode ?? item.code ?? item.id}</td><td>${item.customerName ?? item.customer?.name ?? ''}</td><td>${item.roomName ?? item.room?.name ?? ''}</td><td>${item.checkOutAt ?? item.time ?? ''}</td></tr>`).join('');
const overdueRows = overdueItems.map((item) => `<tr><td>${item.invoiceCode ?? item.code ?? item.id}</td><td>${item.customerName ?? item.customer?.name ?? ''}</td><td>${Number(item.amount ?? item.remainingAmount ?? 0).toLocaleString('vi-VN')}</td><td>${item.dueDate ?? ''}</td></tr>`).join('');

const html = `
  <h2>Bao cao van hanh ngay ${config.reportDate}</h2>
  <h3>Chi so chinh</h3>
  <table border="1" cellpadding="8" cellspacing="0">
    <tr><td>Ty le lap day</td><td>${occupancyRate}%</td></tr>
    <tr><td>Phong trong</td><td>${vacantRooms}/${totalRooms}</td></tr>
    <tr><td>Check-in hom nay</td><td>${checkIns.length}</td></tr>
    <tr><td>Check-out hom nay</td><td>${checkOuts.length}</td></tr>
    <tr><td>Cong no qua han</td><td>${Number(overdueAmount).toLocaleString('vi-VN')} VND</td></tr>
  </table>
  <h3>Danh sach check-in</h3>
  <table border="1" cellpadding="8" cellspacing="0"><tr><th>Ma</th><th>Khach</th><th>Phong</th><th>Gio</th></tr>${checkInRows || '<tr><td colspan="4">Khong co</td></tr>'}</table>
  <h3>Danh sach check-out</h3>
  <table border="1" cellpadding="8" cellspacing="0"><tr><th>Ma</th><th>Khach</th><th>Phong</th><th>Gio</th></tr>${checkOutRows || '<tr><td colspan="4">Khong co</td></tr>'}</table>
  <h3>Cong no qua han</h3>
  <table border="1" cellpadding="8" cellspacing="0"><tr><th>Hoa don</th><th>Khach</th><th>So tien</th><th>Han thanh toan</th></tr>${overdueRows || '<tr><td colspan="4">Khong co</td></tr>'}</table>
`;

const summaryText = `Bao cao van hanh ${config.reportDate}\nOccupancy: ${occupancyRate}%\nPhong trong: ${vacantRooms}/${totalRooms}\nCheck-in: ${checkIns.length}\nCheck-out: ${checkOuts.length}\nCong no qua han: ${Number(overdueAmount).toLocaleString('vi-VN')} VND`;

return {
  json: {
    ...config,
    report: {
      checkIns: checkIns.length,
      checkOuts: checkOuts.length,
      occupancyRate,
      vacantRooms,
      totalRooms,
      overdueCount: overdueItems.length,
      overdueAmount,
      html,
      summaryText,
    },
    email: {
      from: config.smtpFrom,
      to: config.managerEmails.join(','),
      subject: `Bao cao van hanh khach san - ${config.reportDate}`,
      html,
    },
    slackPayload: {
      text: `*Bao cao van hanh ${config.reportDate}*\n${summaryText}`,
    },
    telegramPayload: {
      chat_id: config.telegramChatId,
      text: summaryText,
    },
  },
};

const current = $json;
const config = $('Build Daily Report').item.json;
const error = current.error ?? current.message?.error;
return {
  json: {
    hasError: Boolean(error),
    technicalAlertWebhookUrl: config.technicalAlertWebhookUrl,
    alertPayload: {
      text: `Daily report distribution issue\nDate: ${config.reportDate}\nNode output: ${JSON.stringify(current).slice(0, 1200)}`,
    },
  },
};
